const product = $('Loop Over Items').item.json;

const knownKeys =
  $('category_keys_context').item.json?.keys_context ?? {};

const isPlainObject = (v) =>
  v !== null &&
  typeof v === 'object' &&
  !Array.isArray(v);

const isEmpty = (v) =>
  v === null ||
  v === undefined ||
  v === '' ||
  (Array.isArray(v) && v.length === 0) ||
  (isPlainObject(v) && Object.keys(v).length === 0);

const clean = (obj) =>
  Object.fromEntries(Object.entries(obj).filter(([, v]) => !isEmpty(v)));

const llmInput = {
  ...clean({
    category_name: product.category_name,
    specs: product.specs,
  }),
  keys_context: isPlainObject(knownKeys) ? knownKeys : {},
};

return { llmInput: JSON.stringify(llmInput) };

const product = $('Loop Over Items').item.json
const raw = $input.item.json

const reviewOut = (error_type, detail) => ({
  json: {
    status: 'review',
    success: false,
    product_id: product.id,
    category_id: product.category_id,
    product_slug: product.slug,
    error_type,
    error_detail: detail,
  }
})

const tryParse = (s) => {
  try {
    return JSON.parse(s)
  } catch {
    return null
  }
}

const tryParseLoose = (s) => {
  if (typeof s !== 'string') return null
  let t = s.trim()
  const fence = t.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i)
  if (fence) t = fence[1].trim()
  let p = tryParse(t)
  if (p) return p
  const a = t.indexOf('{'), b = t.lastIndexOf('}')
  if (a !== -1 && b > a) p = tryParse(t.slice(a, b + 1))
  return p
}

const isPlainObj = (o) => o && typeof o === 'object' && !Array.isArray(o)
const uniq = (arr) => [...new Set(arr)
]
const preview = (x, n = 800) => {
  try {
    return JSON.stringify(x).slice(0, n)
  } catch {
    return String(x).slice(0, n)
  }
}

const autoFixes = []
const violations = []
const keyAliases = new Map()

const addFix = (s) => autoFixes.push(s)
const addViolation = (s) => violations.push(s)

// ------------------------------------------------------------------
// 1) Parse OpenAI/n8n wrapper, then enforce prompt-level contract:
//    exactly { audit_trace, output, keys_context }.
// ------------------------------------------------------------------
let parsed

if (typeof raw === 'string') {
  parsed = tryParseLoose(raw)
} else if (typeof raw?.output === 'string') {
  parsed = tryParseLoose(raw.output)
} else if (typeof raw?.text === 'string') {
  parsed = tryParseLoose(raw.text)
} else if (typeof raw?.message?.content === 'string') {
  parsed = tryParseLoose(raw.message.content)
} else if (
  isPlainObj(raw?.output) &&
  isPlainObj(raw.output.audit_trace) &&
  isPlainObj(raw.output.output) &&
  isPlainObj(raw.output.keys_context)
) {
  parsed = raw.output
} else {
  parsed = raw
}

if (!isPlainObj(parsed)) {
  return reviewOut('invalid_json',
    {
      raw_preview: preview(raw)
    })
}

const expectedTop = ['audit_trace', 'keys_context', 'output'
]
const actualTop = Object.keys(parsed).sort()
const contractOk =
  actualTop.length === expectedTop.length &&
  actualTop.every((k, i) => k === expectedTop[i
  ])

// Tolerant recovery instead of a hard reject. code.js re-derives keys_context
// from the final specs, auto-initializes audit_trace, and recovers a missing
// output from raw specs (empty-output net below) — only `output` is truly
// load-bearing. A response that renames/omits top-level keys is RECOVERED and
// logged; genuinely empty results still route to review downstream
// (empty_normalization / coverage_gap).
if (!contractOk) {
  const missingTop = expectedTop.filter((k) => !isPlainObj(parsed[k
  ]))
  addFix('contract_deviation_recovered:actual=' + (actualTop.join('+') || 'none') + ':missing=' + (missingTop.join('+') || 'none'))
}

const auditTrace = isPlainObj(parsed.audit_trace) ? {
  ...parsed.audit_trace
} : {}
let specs = isPlainObj(parsed.output) ? {
  ...parsed.output
} : {}
const llmKeysContext = isPlainObj(parsed.keys_context) ? {
  ...parsed.keys_context
} : {}

// Recover a keys_context the model nested INSIDE output (contract drift): lift it
// into llmKeysContext so it is not later flagged as a nested_object inside specs.
if (!isPlainObj(parsed.keys_context) && isPlainObj(specs.keys_context)) {
  Object.assign(llmKeysContext, specs.keys_context)
  delete specs.keys_context
  addFix('lifted_nested_keys_context_from_output')
}

const AUDIT_ARRAY_KEYS = [
  'identity_discards',
  'unit_conversions',
  'keys_context_dedup_hits',
  'shape_decisions',
  'narrative_vs_enum',
  'compliance_merges',
  'composite_parsing',
  'casing_translation',
  'unmapped_specs',
]

for (const k of AUDIT_ARRAY_KEYS) {
  if (!Array.isArray(auditTrace[k
  ])) {
    auditTrace[k
    ] = []
    addFix(`audit_array_initialized:${k
      }`)
  }
}

if (!isPlainObj(auditTrace.self_check)) {
  auditTrace.self_check = {}
  addFix('audit_self_check_initialized')
}

const pushAudit = (k, entry) => {
  if (!Array.isArray(auditTrace[k
  ])) auditTrace[k
  ] = []
  auditTrace[k
  ].push(entry)
}

