// ------------------------------------------------------------------
// Reference data (DB-backed, with in-code fallback).
// An upstream node exposes the `reference_bundle` view as rows
// { kind, map }. We MERGE that over the *_FALLBACK literals so an
// empty/absent bundle reproduces the previous hardcoded behavior
// EXACTLY. code.js stays the enforcement authority; the prompt keeps
// its static lists as guidance. SEGMENT_MAP is intentionally NOT
// externalized (per-segment application of arbitrary equivalences is
// unsafe); only the whole-key EXACT_KEY_MAP is data-driven.
// ------------------------------------------------------------------
const readReferenceBundle = () => {
  try {
    const node = $('Reference Bundle') // <- rename to your reference node
    const rows = typeof node?.all === 'function' ? node.all() : [node?.first?.()]
    const out = {}
    for (const it of rows) {
      const row = it?.json ?? it
      if (isPlainObj(row) && typeof row.kind === 'string' && isPlainObj(row.map)) {
        out[row.kind] = row.map
      }
    }
    return out
  } catch {
    return {}
  }
}

const REF_BUNDLE = readReferenceBundle()
const pickMap = (k) => (isPlainObj(REF_BUNDLE[k]) ? REF_BUNDLE[k] : {})

