const deepEqual = (a, b) => JSON.stringify(a) === JSON.stringify(b)
const isFiniteNumber = (x) => typeof x === 'number' && Number.isFinite(x)

const getUnitSuffix = (k) => {
  const range = k.match(RANGE_KEY_RE)
  if (range) return range[
    3
  ]

  const m = k.match(NUMERIC_UNIT_RE)
  return m ? m[
    1
  ] : null
}

const isRangeKey = (k) => RANGE_KEY_RE.test(k)
// A min/max key is only a true range endpoint if its opposite endpoint
// (same root + unit) is also present. Standalone "_max_<unit>" keys like
// wifi_5ghz_max_mbps are scalar capabilities, not range endpoints.
const isPairedRangeKey = (k) => {
  const m = k.match(RANGE_KEY_RE)
  if (!m) return false
  const opposite = `${m[1]}_${m[2] === 'min' ? 'max' : 'min'}_${m[3]}`
  return opposite in specs
}
const hasNarrativeSuffix = (k) => NARRATIVE_SUFFIXES.some((s) => k.endsWith(s))

const tokenLooksShortEnum = (arr) => {
  if (!Array.isArray(arr) || !arr.every((x) => typeof x === 'string')) return false
  if (arr.length === 0) return false

  const longest = arr.reduce((a, b) => (b.length > a.length ? b : a), '')
  return longest.length <= 30 && !/[.;]/.test(longest)
}

const normalizeProtocolToken = (s) => {
  let t = s.trim().toLowerCase().replace(/[_\s]+/g, ' ').trim()
  t = t.replace(/^rs\s*-?\s*232$/, 'rs-232')
  t = t.replace(/^rs\s*-?\s*485$/, 'rs-485')
  t = t.replace(/^rs\s*-?\s*422$/, 'rs-422')
  t = t.replace(/^wi\s*-?\s*fi$/, 'wifi')
  return t
}

const translateEnumToken = (s) => VALUE_TRANSLATIONS[s
] ?? s

const translateNarrative = (s) => {
  let out = s.trim()

  for (const [from, to
  ] of Object.entries(VALUE_TRANSLATIONS)) {
    const re = new RegExp(`\\b${from.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'gi')
    out = out.replace(re, to)
  }

  return out
}

const parseBooleanish = (v) => {
  if (typeof v === 'boolean') return {
    ok: true, value: v
  }
  if (typeof v !== 'string') return {
    ok: false
  }

  const t = v.trim().toLowerCase()

  if (['true', 'yes', 'si', 'sí', 'y', '1'
  ].includes(t)) {
    return {
      ok: true, value: true
    }
  }

  if (['false', 'no', 'n', '0'
  ].includes(t)) {
    return {
      ok: true, value: false
    }
  }

  return {
    ok: false
  }
}

const numericPattern = '[+-]?(?:\\d+(?:\\.\\d*)?|\\.\\d+)'

const unitPatterns = {
