const parseNumericStringForKey = (k, rawValue) => {
  if (typeof rawValue !== 'string') return {
    ok: false
  }

  const t = rawValue.trim().toLowerCase().replace(',', '.')
  if (t === '') return {
    ok: false
  }

  if (new RegExp(`^${numericPattern
    }$`).test(t)) {
    const n = Number(t)
    return Number.isFinite(n)
      ? {
        ok: true, value: n, reason: 'pure_numeric_string'
      }
      : {
        ok: false
      }
  }

  const unit = getUnitSuffix(k)
  if (!unit || !unitPatterns[unit
  ]) return {
    ok: false
  }

  for (const u of unitPatterns[unit
  ]) {
    if (u === '') continue

    const re = new RegExp(
      `^(${numericPattern})\\s*${u.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$`,
      'i'
    )

    const m = t.match(re)

    if (m) {
      const n = Number(m[
        1
      ])
      return Number.isFinite(n)
        ? {
          ok: true, value: n, reason: `stripped_redundant_unit:${unit
            }`
        }
        : {
          ok: false
        }
    }
  }

  return {
    ok: false
  }
}

const normalizeKeyFormat = (key) => {
  let k = String(key).trim()

  for (const [re, repl
  ] of ACRONYM_REPLACEMENTS) {
    k = k.replace(re, repl)
  }

  k = k.replace(/([A-Z]+)([A-Z][a-z])/g, '$1_$2')
  k = k.replace(/([a-z0-9])([A-Z])/g, '$1_$2')
  k = k.toLowerCase()
  k = k.normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  k = k
    .replace(/[^a-z0-9_]/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+/, key.startsWith('_') ? '_' : '')
    .replace(/_+$/, '')

  if (k !== '_' && k.startsWith('__')) {
    k = `_${k.replace(/^_+/, '')
      }`
  }

  return k
}

const applyKeyEquivalences = (k) => {
  let nk = k

  if (nk.startsWith('device_')) nk = nk.slice('device_'.length)
  if (nk.startsWith('product_')) nk = nk.slice('product_'.length)
  if (nk.startsWith('item_')) nk = nk.slice('item_'.length)

  const bare = nk.startsWith('_') ? nk.slice(1) : nk
  const prefix = nk.startsWith('_') ? '_' : ''

  if (EXACT_KEY_MAP[bare
  ]) return prefix + EXACT_KEY_MAP[bare
  ]

  const mapped = bare
    .split('_')
    .map((seg) => SEGMENT_MAP[seg
    ] ?? seg)
    .join('_')

  return prefix + mapped
}

const fixRangeUnitOrder = (k) => {
  const m = k.match(BAD_RANGE_ORDER_RE)
  if (!m) return k

  return `${m[
    1
  ]
    }_${m[
    3
    ]
    }_${m[
    2
    ]
    }`
}

const mergeValues = (existing, incoming) => {
  if (deepEqual(existing, incoming)) return {
    ok: true, value: existing
  }

  if (Array.isArray(existing) && Array.isArray(incoming)) {
    const joined = [...existing, ...incoming
    ]
    const types = new Set(joined.map((x) => typeof x))

    if (types.size === 1 && (types.has('string') || types.has('number'))) {
      return {
        ok: true, value: uniq(joined)
      }
    }
  }

  if (Array.isArray(existing) && !Array.isArray(incoming)) {
    const types = new Set(existing.map((x) => typeof x))

    if (
      types.size === 1 &&
      types.has(typeof incoming) &&
      ['string', 'number'
      ].includes(typeof incoming)
    ) {
      return {
        ok: true, value: uniq([...existing, incoming
        ])
      }
    }
  }

  if (!Array.isArray(existing) && Array.isArray(incoming)) {
    const types = new Set(incoming.map((x) => typeof x))

    if (
      types.size === 1 &&
      types.has(typeof existing) &&
      ['string', 'number'
      ].includes(typeof existing)
    ) {
      return {
        ok: true, value: uniq([existing, ...incoming
        ])
      }
    }
  }

  return {
    ok: false
  }
}

const renameKey = (oldKey, newKey, reason) => {
  if (oldKey === newKey) return true
  if (!(oldKey in specs)) return true

  if (newKey in specs) {
    const merged = mergeValues(specs[newKey
    ], specs[oldKey
    ])

    if (!merged.ok) {
      addViolation(`key_collision:${oldKey
        }->${newKey
        }`)
      return false
    }

    specs[newKey
    ] = merged.value
    delete specs[oldKey
    ]
    keyAliases.set(oldKey, newKey)
    addFix(`${reason
      }:${oldKey
      }->${newKey
      }:merged`)
    return true
  }

  specs[newKey
  ] = specs[oldKey
    ]
  delete specs[oldKey
  ]
  keyAliases.set(oldKey, newKey)
  addFix(`${reason
    }:${oldKey
    }->${newKey
    }`)
  return true
}

const addCertification = (token, sourceLabel) => {
  specs.certifications = Array.isArray(specs.certifications)
    ? specs.certifications
    : specs.certifications
      ? [specs.certifications
      ]
      : []

  specs.certifications.push(token)

  pushAudit('compliance_merges',
    {
      raw_boolean: sourceLabel,
      added_to_certifications: token,
    })
}

const normalizeCertToken = (rawCert) => {
  if (typeof rawCert !== 'string') {
    return {
      ok: false, violation: `non_string_certification:${String(rawCert)
        }`
    }
  }

  const trimmed = rawCert.trim()

  if (trimmed === '') {
    return {
      ok: true, drop: true, reason: 'empty_certification'
    }
  }

  if (PENDING_CERT_RE.test(trimmed)) {
    return {
      ok: true, drop: true, reason: 'pending_certification'
    }
  }

  if (CERT_ALLOWED.has(trimmed)) {
    return {
      ok: true, value: trimmed
    }
  }

  const low = trimmed.toLowerCase().replace(/\s+/g, ' ')

  if (CERT_MAP[low
  ]) return {
    ok: true, value: CERT_MAP[low
    ]
  }

  if (/\bsubtel\b/.test(low)) return {
    ok: true, value: 'CL-SUBTEL'
  }
  if (/\bursec\b/.test(low)) return {
    ok: true, value: 'UY-URSEC'
  }
  if (/\benacom\b/.test(low)) return {
    ok: true, value: 'AR-ENACOM'
  }
  if (/\banatel\b/.test(low)) return {
    ok: true, value: 'BR-ANATEL'
  }
  if (/\bifetel\b/.test(low)) return {
    ok: true, value: 'MX-IFETEL'
  }
  if (/\bfcc\b/.test(low)) return {
    ok: true, value: 'GLOBAL-FCC'
  }
  if (/\bce\b/.test(low)) return {
    ok: true, value: 'GLOBAL-CE'
  }
  if (/\brohs\b/.test(low)) return {
    ok: true, value: 'GLOBAL-RoHS'
  }
  if (/\breach\b/.test(low)) return {
    ok: true, value: 'GLOBAL-REACH'
  }
  if (/\braee\b/.test(low)) return {
    ok: true, value: 'GLOBAL-WEEE'
  }
  if (/\bweee\b/.test(low)) return {
    ok: true, value: 'GLOBAL-WEEE'
  }
  if (/\bnyce\b/.test(low)) return {
    ok: true, value: 'MX-NYCE'
  }

  return {
    ok: false, violation: `unknown_certification_token:${trimmed
      }`
  }
}

// ------------------------------------------------------------------
// 1b) Empty-output safety net.
//     The LLM is the primary extractor. It occasionally returns
//     output:{} for trivially-mappable products (e.g. an antenna whose
//     keys_context already contains every target key). When that happens
//     AND raw specs exist, deterministically map the unambiguous Spanish
//     labels so the product is not lost to `empty_normalization`. The
//     recovered object then flows through the SAME key/value normalization
//     and the SAME hard-validation pass below — this net only re-seeds
//     `specs`, it does not bypass any rule. Extend FALLBACK_LABEL_MAP with
//     labels that are unambiguous across categories; keep guessy ones out.
// ------------------------------------------------------------------
const fbLc = (s) => String(s).normalize('NFD').replace(/[̀-ͯ]/g, '').trim().toLowerCase()
const fbFirstNumber = (s) => { const m = String(s).replace(',', '.').match(/[+-]?(?:\d+(?:\.\d+)?|\.\d+)/); return m ? Number(m[0]) : null }
const fbAllNumbers = (s) => (String(s).replace(/,/g, '.').match(/[+-]?(?:\d+(?:\.\d+)?|\.\d+)/g) || []).map(Number).filter(Number.isFinite)

const FALLBACK_LABEL_MAP = {
  'ganancia': (v) => ({ gain_dbi: fbFirstNumber(v) }),
  'vswr': (v) => ({ vswr_max: fbFirstNumber(v) }),
  'polarizacion': (v) => ({ polarization: [fbLc(v)] }),
  'impedancia': (v) => ({ impedance_ohm: fbFirstNumber(v) }),
  'potencia maxima de entrada': (v) => ({ input_power_max_w: fbFirstNumber(v) }),
  'tipo de cable': (v) => ({ cable_type: [fbLc(v).replace(/[^a-z0-9]+/g, '')] }),
  'longitud': (v) => { const n = fbFirstNumber(v); if (n == null) return {}; const low = fbLc(v); if (/\bmm\b/.test(low)) return { length_mm: n }; if (/\bcm\b/.test(low)) return { length_mm: Math.round(n * 10) }; return { length_mm: Math.round(n * 1000) } },
  'conector': (v) => ({ connector: [fbLc(v).replace(/\bmacho\b/, 'male').replace(/\bhembra\b/, 'female').replace(/\s+/g, '-')] }),
  'rango de frecuencia': (v) => { const ns = fbAllNumbers(v).map(Math.abs); return ns.length ? { frequency_min_mhz: Math.min(...ns), frequency_max_mhz: Math.max(...ns) } : {} },
