}

const extractFromRawSpecs = (rawSpecs) => {
  const out = {}

  for (const sp of rawSpecs) {
    if (!isPlainObj(sp)) continue

    const handler = FALLBACK_LABEL_MAP[fbLc(sp.name ?? '')]

    if (!handler) {
      pushAudit('unmapped_specs', { raw_name: sp?.name, raw_value: sp?.value, reason: 'low_confidence' })
      continue
    }

    const got = handler(String(sp.value ?? ''))

    for (const [k, val
    ] of Object.entries(got)) {
      if (val === null || val === undefined || (Array.isArray(val) && val.length === 0)) continue
      out[k
      ] = val
    }
  }

  return out
}

