// Split dimensions_mm numeric triple into children.
// String composites are rejected later unless the model already emitted child keys.
if (
  Array.isArray(specs.dimensions_mm) &&
  specs.dimensions_mm.length === 3 &&
  specs.dimensions_mm.every(isFiniteNumber)
