// ------------------------------------------------------------------
// 3) Value-level deterministic normalization.
// ------------------------------------------------------------------
const reroutedStandards = []

for (const k of [...Object.keys(specs)
]) {
  if (!(k in specs)) continue

  let v = specs[k
  ]

  const emptyPlainObj = isPlainObj(v) && Object.keys(v).length === 0

  if (
    v === null ||
    v === undefined ||
    v === '' ||
    emptyPlainObj ||
    (Array.isArray(v) && v.length === 0)
  ) {
    delete specs[k
    ]
    addFix(`dropped_empty:${k
