    const out = []

    for (const c of arr) {
      const normalized = normalizeCertToken(c)

      if (!normalized.ok) {
        const tok = String(c).trim()

        if (STANDARD_TOKEN_RE.test(tok)) {
          reroutedStandards.push(tok.toLowerCase())
          addFix(`rerouted_standard_from_certifications:${tok
            }`)
          continue
        }

        addViolation(normalized.violation)
        continue
      }

      if (normalized.drop) {
        addFix(`dropped_certification:${String(c).trim()
          }:${normalized.reason
          }`)
        continue
      }

      out.push(normalized.value)

      if (normalized.value !== c) {
        addFix(`normalized_certification:${String(c).trim()
          }->${normalized.value
          }`)
      }
    }

    const deduped = uniq(out)

    if (deduped.length === 0) {
      delete specs[k
      ]
    } else {
      specs[k
      ] = deduped
    }

    continue
  }

  const unit = getUnitSuffix(k)

  if (typeof v === 'string') {
    const b = parseBooleanish(v)

    if (b.ok && k.startsWith('has_')) {
      specs[k
      ] = b.value
      addFix(`boolean_string_normalized:${k
        }`)
      continue
    }

    const parsedNumber = parseNumericStringForKey(k, v)

    if (parsedNumber.ok && unit) {
      specs[k
      ] = parsedNumber.value
      addFix(`numeric_string_normalized:${k
        }:${parsedNumber.reason
        }`)
      continue
    }

    const trimmed = v.trim()

    if (trimmed === '') {
      delete specs[k
