  if (Array.isArray(v)) {
    let arr = v.filter((x) => !(typeof x === 'string' && x.trim() === ''))

    if (unit) {
      const numericOut = []

      for (const item of arr) {
        if (isFiniteNumber(item)) {
          numericOut.push(item)
          continue
        }

        const parsedNumber = parseNumericStringForKey(k, item)

        if (parsedNumber.ok) {
          numericOut.push(parsedNumber.value)
          addFix(`numeric_array_item_normalized:${k
            }:${String(item).trim()
            }`)
          continue
        }

        const rng = String(item).trim().toLowerCase().replace(',', '.').match(/^([+-]?(?:\d+(?:\.\d*)?|\.\d+))\s*[-–~]\s*([+-]?(?:\d+(?:\.\d*)?|\.\d+))/)

        if (rng && arr.length === 1 && !RANGE_KEY_RE.test(k)) {
          const base = k.replace(NUMERIC_UNIT_RE, '')
          specs[`${base
            }_min_${unit
            }`] = Number(rng[
              1
            ])
          specs[`${base
            }_max_${unit
            }`] = Number(rng[
              2
            ])
          addFix(`split_range_string:${k
            }->${base
            }_min_${unit
            },${base
            }_max_${unit
            }`)
          continue
        }

        pushAudit('unmapped_specs', {
          raw_name: k, raw_value: String(item), reason: 'unparseable'
        })
        addFix(`dropped_unparseable_numeric:${k
          }=${String(item)
          }`)
      }

      const deduped = uniq(numericOut)

      if (deduped.length === 0) {
        delete specs[k
        ]
      } else {
        specs[k
        ] = deduped.length === 1 ? deduped[
          0
        ] : deduped
      }

      continue
    }

    const types = new Set(arr.map((x) => typeof x))

    if (types.size > 1) {
      addViolation(`mixed_array:${k
        }`)
      continue
    }

    if (types.has('number')) {
      if (!arr.every(isFiniteNumber)) {
        addViolation(`non_finite_number_in_array:${k
          }`)
      }

      const deduped = uniq(arr)

      specs[k
      ] = deduped.length === 1 ? deduped[
