          .map((x) => translateNarrative(String(x)))
          .filter((x) => x !== '')

        specs[k
        ] = uniq(out)
      } else {
        const out = arr
          .map((x) => translateEnumToken(normalizeProtocolToken(String(x))))
          .filter((x) => x !== '')

        specs[k
        ] = uniq(out)
      }

      if (specs[k
      ].length === 0) {
        delete specs[k
        ]
        addFix(`dropped_empty_array_after_cleanup:${k
          }`)
      }

      continue
    }

    addViolation(`invalid_array_type:${k
      }`)
    continue
  }
