  if (hasNarrativeSuffix(k)) continue

  const v = specs[k
  ]
  const bare = k.slice(1)

  if (Array.isArray(v) && tokenLooksShortEnum(v)) {
    renameKey(k, bare, 'stripped_enum_underscore')

    pushAudit('narrative_vs_enum',
      {
