}
// Final cleanup of empties after renames.
for (const [k, v
] of Object.entries(specs)) {
  if (
    v === null ||
    v === undefined ||
    v === '' ||
    (Array.isArray(v) && v.length === 0) ||
    (isPlainObj(v) && Object.keys(v).length === 0)
