    delete specs[k
    ]
    addFix(`dropped_empty_final:${k
      }`)
  }
}
// ------------------------------------------------------------------
// 3b) Relocate regulatory APPROVAL MARKS misfiled under regulatory_standards.
//     regulatory_standards is a free enum, so a cert token (weee/raee/rohs/
