//     never the loose word-boundary fallback — so technical standards
//     (en 55032, iec 61000-*, mil-std-810g) stay put. Pending marks are skipped.
// ------------------------------------------------------------------
const certHit = (tok) => {
  if (typeof tok !== 'string') return null
  const t = tok.trim()
  if (!t || PENDING_CERT_RE.test(t)) return null
