if (Array.isArray(specs.certifications)) specs.certifications = uniq(specs.certifications)
// ------------------------------------------------------------------
// 4) Hard validation pass. Authority is the real normalized output.
// ------------------------------------------------------------------
for (const [k, v
] of Object.entries(specs)) {
  const bare = k.startsWith('_') ? k.slice(1) : k

  if (k.startsWith('_')) {
    if (!/^_[a-z0-9]+(?:_[a-z0-9]+)*$/.test(k)) {
