      }`)
  }

  if (IDENTITY_KEYS.has(bare) || IDENTITY_SEGMENT_RE.test(bare)) {
    addViolation(`identity_key:${k
      }`)
  }

  if (k.startsWith('_') && IDENTITY_SEGMENT_RE.test(bare)) {
    addViolation(`identity_disguised:${k
      }`)
  }

  if (isPlainObj(v)) addViolation(`nested_object:${k
    }`)
  if (v === null || v === undefined) addViolation(`null_or_undefined:${k
    }`)
  if (typeof v === 'string') addViolation(`scalar_string_forbidden:${k
    }`)
  if (Array.isArray(v) && v.length === 0) addViolation(`empty_array:${k
    }`)

  if (typeof v === 'boolean') {
    if (!k.startsWith('has_')) addViolation(`boolean_without_has_prefix:${k
      }`)
    if (BAD_BOOL_PREFIX_RE.test(k)) addViolation(`bad_bool_prefix:${k
      }`)
  }

  if (/^(has_)?(rohs|ce|fcc|reach)_compliant$/.test(k)) {
    addViolation(`standalone_compliant_key:${k
      }`)
  }

  if (hasNarrativeSuffix(k) && !k.startsWith('_')) {
    addViolation(`bare_narrative_key:${k
      }`)
  }

  if (k.startsWith('_')) {
    if (!Array.isArray(v) || !v.every((x) => typeof x === 'string' && x.trim() !== '')) {
      addViolation(`narrative_value_must_be_string_array:${k
        }`)
    } else if (!hasNarrativeSuffix(k) && tokenLooksShortEnum(v)) {
      addViolation(`enum_with_underscore:${k
        }`)
    }
  }

  if (Array.isArray(v)) {
    const types = new Set(v.map((x) => typeof x))

    if (types.size > 1) addViolation(`mixed_array:${k
      }`)

    if (types.has('string')) {
      for (const x of v) {
        if (typeof x !== 'string') {
          addViolation(`non_string_in_string_array:${k}=${String(x)}`)
          continue
        }

        if (x.trim() !== x || x === '') {
          addViolation(`bad_string_token:${k}=${x}`)
        }

        if (k !== 'certifications' && !k.startsWith('_') && x !== x.toLowerCase()) {
          addViolation(`enum_not_lowercase:${k}=${x}`)
        }
      }
    }

    if (types.has('number')) {
      if (!v.every(isFiniteNumber)) {
        addViolation(`non_finite_number_in_array:${k
          }`)
      }

      if (!getUnitSuffix(k)) {
        addViolation(`numeric_array_without_unit_or_count_suffix:${k
          }`)
      }
    }

    if (uniq(v).length !== v.length) {
      addViolation(`duplicate_array_values:${k
        }`)
    }
  }

  if (BAD_RANGE_ORDER_RE.test(k)) {
    addViolation(`unit_not_final_segment:${k
      }`)
  }

  if (isPairedRangeKey(k) && !isFiniteNumber(v)) {
    addViolation(`range_endpoint_must_be_number:${k
      }`)
  }

  if (RANGE_KEY_RE.test(k) && Array.isArray(v)) {
    addViolation(`array_in_minmax_key:${k
      }`)
  }

  if (NON_CANONICAL_UNIT_RE.test(k)) {
    addViolation(`non_canonical_unit:${k
      }`)
  }

  if (k.endsWith('_hours') && !RELIABILITY_HOURS_OK_RE.test(k)) {
    addViolation(`non_canonical_hours:${k
      }`)
  }

  if ((k.endsWith('_years') || k.endsWith('_months')) && !RELIABILITY_YEARS_MONTHS_OK_RE.test(k)) {
    addViolation(`non_canonical_years_months:${k
      }`)
  }

  if (getUnitSuffix(k) && Array.isArray(v) && v.some((x) => typeof x === 'string')) {
    addViolation(`string_in_numeric_key:${k
      }`)
  }

  if (k === 'certifications') {
    if (!Array.isArray(v) || !v.every((x) => typeof x === 'string' && CERT_ALLOWED.has(x))) {
      addViolation('invalid_certifications_array')
    }
  }
}
// Parent/child conflicts and forbidden parents.
const hasAny = (...keys) => keys.some((k) => k in specs)

if ('dimensions_mm' in specs && hasAny('length_mm', 'width_mm', 'height_mm', 'depth_mm')) {
  addViolation('parent_child_conflict:dimensions_mm')
}

if ('ethernet_ports' in specs && hasAny('ethernet_lan_ports_count', 'ethernet_wan_ports_count')) {
  addViolation('parent_child_conflict:ethernet_ports')
}

if ('serial_esd_v' in specs && hasAny('serial_esd_air_v', 'serial_esd_contact_v')) {
  addViolation('parent_child_conflict:serial_esd_v')
}

if ('inputs' in specs && hasAny('digital_inputs_count', 'analog_inputs_count')) {
  addViolation('parent_child_conflict:inputs')
}

if ('dimensions_mm' in specs) {
  addViolation('forbidden_parent_key:dimensions_mm')
}
// Scalar + range conflict for same base/unit.
const scalarKeys = new Set(Object.keys(specs))

for (const k of Object.keys(specs)) {
  const m = k.match(RANGE_KEY_RE)

  if (!m) continue

  const scalar = `${m[
    1
  ]
    }_${m[
    3
    ]
    }`

  if (scalarKeys.has(scalar)) {
    delete specs[scalar]
    scalarKeys.delete(scalar)
    addFix(`dropped_scalar_kept_range:${scalar
      }<->${k
      }`)
  }
}
// Propagate deterministic key renames into the audit so it stays truthful for downstream RAG/JSONB.
const resolveAlias = (k) => { let cur = k, guard = 0; while (keyAliases.has(cur) && guard++ < 50) cur = keyAliases.get(cur); return cur }

for (const e of auditTrace.unit_conversions) {
  if (isPlainObj(e) && typeof e.emitted_key === 'string') {
    const r = resolveAlias(e.emitted_key)
    if (r !== e.emitted_key) {
      addFix(`audit_emitted_key_realiased:${e.emitted_key
        }->${r
        }`)
      e.emitted_key = r
    }
  }
}
// The audit cross-checks below are ADVISORY ONLY. They validate the model's self-narration,
// not the normalized output (which is fully validated above). They record fixes, never block.
for (const k of Object.keys(specs).filter(isPairedRangeKey)) {
  const found = auditTrace.unit_conversions.some(
    (e) =>
      isPlainObj(e) &&
      e.emitted_key === k &&
      typeof e.calc === 'string' &&
      /^Calculator\(.+\)$/.test(e.calc)
  )

  if (!found) {
    addFix(`range_endpoint_without_calc_audit:${k
      }`)
  }
}
// Basic unit_conversions shape validation.
for (const [i, e
] of auditTrace.unit_conversions.entries()) {
  if (!isPlainObj(e)) {
    addFix(`audit_bad_unit_conversion_entry:${i
      }`)
    continue
  }

  if (typeof e.calc !== 'string' || !/^Calculator\(.+\)$/.test(e.calc)) {
    addFix(`audit_weak_calculator_call:${i
      }`)
  }

  if (typeof e.emitted_key !== 'string' || !(e.emitted_key in specs)) {
    addFix(`audit_emitted_key_orphan:${i
      }`)
  }
}
// Composite parsing shape validation when present.
for (const [i, e
] of auditTrace.composite_parsing.entries()) {
  if (!isPlainObj(e)) {
    addFix(`audit_bad_composite_parsing_entry:${i
      }`)
    continue
  }

  if (
    !Array.isArray(e.calculator_verifications) ||
    e.calculator_verifications.some(
      (x) => typeof x !== 'string' || !/^\s*Calculator\(.+\)/.test(x)
    )
  ) {
    addFix(`audit_weak_composite_verifications:${i
      }`)
  }

  if (!isPlainObj(e.emitted)) {
    addFix(`audit_bad_composite_emitted_object:${i
      }`)
  }
}

const hadSpecs = Array.isArray(product.specs) && product.specs.length > 0

if (Object.keys(specs).length === 0) {
  if (!hadSpecs) {
    return {
      json: {
        status: 'skip',
        success: true,
        no_specs: true,
        product_id: product.id,
        category_id: product.category_id,
        product_slug: product.slug,
        specs_normalized: {},
        keys_context: {},
        audit_trace: auditTrace,
        auto_fixes: autoFixes,
      }
    }
  }

  return reviewOut('empty_normalization',
    {
      had_specs: product.specs.length,
      identity_discards: auditTrace.identity_discards,
      unmapped_specs: auditTrace.unmapped_specs,
      auto_fixes: autoFixes,
    })
}
// ------------------------------------------------------------------
// 5) Reconcile output keys_context against final specs.
//    specs is authority. Context is auxiliary, but final contract must be exact.
// ------------------------------------------------------------------
const VALID_SHAPES = new Set(['scalar', 'range', 'enum', 'boolean', 'narrative'
])

const deriveShape = (k, v) => {
  if (typeof v === 'boolean') return 'boolean'
  if (k.startsWith('_')) return 'narrative'
  if (isPairedRangeKey(k)) return 'range'
  if (k === 'certifications') return 'enum'

  if (Array.isArray(v)) {
    if (v.every((x) => typeof x === 'number')) return 'scalar'
    return 'enum'
  }

  return 'scalar'
}

const deriveDesc = (k) => {
  let bare = k.startsWith('_') ? k.slice(1) : k

  const range = bare.match(RANGE_KEY_RE)

  if (range) {
    const qualifier = range[
      2
    ] === 'min' ? 'minimum' : 'maximum'
    bare = `${qualifier
      }_${range[
      1
      ]
      }`
  }

  bare = bare.replace(NUMERIC_UNIT_RE, '')
  bare = bare.replace(/_count$/, ' count')
  bare = bare.replace(/_/g, ' ').replace(/\s+/g, ' ').trim()

  const words = bare.split(' ').filter(Boolean).slice(0,
    8)

  return words.length ? words.join(' ') : 'normalized specification'
}

const findContextSource = (k) => {
  if (isPlainObj(llmKeysContext[k
  ])) return llmKeysContext[k
  ]
  if (k.startsWith('_') && isPlainObj(llmKeysContext[k.slice(1)
  ])) return llmKeysContext[k.slice(1)
  ]
  if (!k.startsWith('_') && isPlainObj(llmKeysContext[`_${k
    }`
  ])) return llmKeysContext[`_${k
    }`
  ]

  for (const [oldKey, newKey
  ] of keyAliases.entries()) {
    if (newKey === k && isPlainObj(llmKeysContext[oldKey
    ])) {
      return llmKeysContext[oldKey
      ]
    }
  }

  return {}
}

const keysContext = {}

for (const [k, v
] of Object.entries(specs)) {
  const src = findContextSource(k)
  const derivedShape = deriveShape(k, v)

  let shape = src.shape

  if (!VALID_SHAPES.has(shape) || shape !== derivedShape) {
    shape = derivedShape
    addFix(`ctx_shape_derived:${k
      }=${shape
      }`)
  }

  let desc = typeof src.desc === 'string' ? src.desc.trim() : ''

  if (desc === '' || desc.split(/\s+/).filter(Boolean).length > 8) {
    desc = deriveDesc(k)
    addFix(`ctx_desc_derived:${k
      }`)
  }

  keysContext[k
  ] = {
    shape, desc
  }
}

const outputKeys = Object.keys(specs).sort()
const contextKeys = Object.keys(keysContext).sort()

if (!deepEqual(outputKeys, contextKeys)) {
  addViolation('keys_context_keyset_mismatch')
}

for (const [k, ctx
] of Object.entries(keysContext)) {
  const badExtraKeys = Object.keys(ctx).filter((x) => !['shape', 'desc'
  ].includes(x))

  if (badExtraKeys.length) {
    addViolation(`keys_context_extra_fields:${k
      }:${badExtraKeys.join(',')
      }`)
  }

  if (!VALID_SHAPES.has(ctx.shape)) {
    addViolation(`keys_context_invalid_shape:${k
      }`)
  }

  if (typeof ctx.desc !== 'string' || ctx.desc.trim() === '') {
    addViolation(`keys_context_missing_desc:${k
      }`)
  }

  if (ctx.desc.split(/\s+/).filter(Boolean).length > 8) {
    addViolation(`keys_context_desc_too_long:${k
      }`)
  }
}

if (violations.length > 0) {
  return reviewOut('semantic_violations',
    {
      violations: uniq(violations),
      auto_fixes: autoFixes,
      audit_trace: auditTrace,
      normalized_preview: specs,
      keys_context_preview: keysContext,
    })
}
// Final computed self-check. We do not trust the LLM self_check as authority.
auditTrace.self_check = Object.fromEntries(
  SELF_CHECK_KEYS.map((k) => [k, 'pass'
  ])
)

const llmCtxOrphans = Object.keys(llmKeysContext).filter((k) => !(k in keysContext))

if (llmCtxOrphans.length) {
  addFix(`ctx_orphans_dropped:${llmCtxOrphans.join(',')
    }`)
}
// ------------------------------------------------------------------
// 5b) Coverage gate. code.js cannot re-extract from raw text, but it CAN
//     detect when the LLM silently dropped WHOLE raw specs and route the
//     product to review instead of letting the loss vanish. Authority for
//     content stays the model; this only catches gross omissions. Partial
//     loss WITHIN one spec (a second labeled sub-range, a second channel)
//     is handled by the prompt, not here.
// ------------------------------------------------------------------
const COVERAGE_MIN_RATIO = 0.70
const COVERAGE_MIN_MISSED = 3
const COVERAGE_MIN_RAW = 4

const rawSpecs = Array.isArray(product.specs) ? product.specs : []

if (rawSpecs.length >= COVERAGE_MIN_RAW) {
  const lc = (s) => String(s).normalize('NFD').replace(/[̀-ͯ]/g, '').toLowerCase()

  const outputNumbers = []
  for (const v of Object.values(specs)) {
    if (isFiniteNumber(v)) outputNumbers.push(v)
    else if (Array.isArray(v)) for (const x of v) if (isFiniteNumber(x)) outputNumbers.push(x)
  }

  const outputTokens = new Set()
  const outputKeyTokens = new Set()
  for (const [k, v] of Object.entries(specs)) {
    for (const seg of k.split('_')) if (seg.length >= 3) outputKeyTokens.add(lc(seg))
    if (Array.isArray(v)) for (const x of v) {
      if (typeof x !== 'string') continue
      for (const tok of lc(x).split(/[^a-z0-9]+/)) if (tok.length >= 3) outputTokens.add(tok)
    }
  }

  const auditTouched = new Set()
  const addTouched = (s) => { if (typeof s === 'string' && s.trim()) auditTouched.add(lc(s.trim())) }
  for (const e of auditTrace.identity_discards) if (isPlainObj(e)) addTouched(e.raw_name)
  for (const e of auditTrace.unmapped_specs) if (isPlainObj(e)) addTouched(e.raw_name)
  for (const e of auditTrace.unit_conversions) if (isPlainObj(e)) addTouched(e.raw)
  for (const e of auditTrace.composite_parsing) if (isPlainObj(e)) addTouched(e.raw)
  for (const e of auditTrace.casing_translation) if (isPlainObj(e)) addTouched(e.raw)
  for (const e of auditTrace.keys_context_dedup_hits) if (isPlainObj(e)) addTouched(e.candidate)
  for (const e of auditTrace.compliance_merges) if (isPlainObj(e)) addTouched(e.raw_boolean)

  const NUM_RE = /[+-]?\d+(?:[.,]\d+)?/g
  const FACTORS = [1, 1000, 0.001, 1e6, 1e-6, 3600]
  const numApproxEqual = (a, b) => Math.abs(a - b) <= (Math.max(Math.abs(a), Math.abs(b)) * 1e-6 + 1e-9)
  const rawNumberCovered = (n) => FACTORS.some((f) => outputNumbers.some((o) => numApproxEqual(o, n * f)))

  const specAccounted = (sp) => {
    const name = lc(String(sp?.name ?? '').trim())
    const valueRaw = String(sp?.value ?? '')
    const value = lc(valueRaw)

    if (name && auditTouched.has(name)) return true

    const nums = (valueRaw.match(NUM_RE) || []).map((m) => Number(m.replace(',', '.'))).filter(Number.isFinite)
    if (nums.some(rawNumberCovered)) return true

    const valTokens = value.split(/[^a-z0-9]+/).filter((t) => t.length >= 3)
    if (valTokens.some((t) => outputTokens.has(t))) return true

    const nameTokens = name.split(/[^a-z0-9]+/).filter((t) => t.length >= 3)
    if (nameTokens.some((t) => {
      const mapped = lc(EXACT_KEY_MAP[t] || SEGMENT_MAP[t] || t)
      return outputKeyTokens.has(t) || outputKeyTokens.has(mapped)
    })) return true

    if (value && [...auditTouched].some((a) => a.length >= 4 && (value.includes(a) || a.includes(value)))) return true

    return false
  }

  const missed = rawSpecs.filter((sp) => !specAccounted(sp))
  const accounted = rawSpecs.length - missed.length
  const coverageRatio = rawSpecs.length ? accounted / rawSpecs.length : 1

  addFix(`coverage:${accounted}/${rawSpecs.length}`)

  if (missed.length >= COVERAGE_MIN_MISSED && coverageRatio < COVERAGE_MIN_RATIO) {
    return reviewOut('coverage_gap', {
      raw_specs: rawSpecs.length,
      accounted,
      missed_count: missed.length,
      coverage_ratio: Number(coverageRatio.toFixed(3)),
      missed_specs: missed.slice(0, 20).map((sp) => ({ name: sp?.name, value: sp?.value })),
      auto_fixes: autoFixes,
      audit_trace: auditTrace,
    })
  }
}
// ------------------------------------------------------------------
// 6) Success.
// ------------------------------------------------------------------
return {
  json: {
    status: 'ok',
    success: true,
    product_id: product.id,
    category_id: product.category_id,
    product_slug: product.slug,
    specs_normalized: specs,
    keys_context: keysContext,
    audit_trace: auditTrace,
    auto_fixes: autoFixes,
    unmapped_specs: auditTrace.unmapped_specs,
  }
}

const items = $input.all();

const isEmpty = (v) =>
  v === null ||
  v === undefined ||
  v === '' ||
  (Array.isArray(v) && v.length === 0) ||
  (typeof v === 'object' && !Array.isArray(v) && Object.keys(v).length === 0);

const clean = (obj) =>
  Object.fromEntries(Object.entries(obj).filter(([, v]) => !isEmpty(v)));

function flattenSpecs(raw) {
  const out = [];

  for (const s of raw || []) {
    let spec = null;

    if (s?.value != null && String(s.value).trim() !== '') {
      spec = {
        name: String(s.name ?? '').trim(),
        value: String(s.value ?? '').trim(),
      };
    } else if (Array.isArray(s?.items) && s.items.length > 0) {
      spec = {
        name: String(s.name ?? '').trim(),
        value: s.items
          .filter(x => typeof x === 'string' && x.trim() !== '')
          .map(x => x.trim())
          .join(' | '),
      };
    }

    if (spec && spec.name && spec.value) {
      if (s?.section != null && String(s.section).trim() !== '') {
        spec.section = String(s.section).trim();
      }

      out.push(spec);
    }
  }

  return out;
}

return items.map(item => {
  const row = item.json;

  return {
    json: clean({
      ...row,
      specs: flattenSpecs(row.specs),
    }),
  };
});

return {
  produtId: $('flatten specs').item.json.id,
  input: $('llm input').item.json.llmInput,
  review: $('post-OpenAI').item.json
};
